; 雪原

name = フーラ雪原・北の森
insideName = North Forest
level = 22
bgm = snow
isOutdoor = true
shadow = dark
sky = snowy
roof = wood
outfield = snow
blank = rock
effect = PE_snow3

; 画像パーツ
━ = wood
－ = soil
　 = snow
☐ = wood
❖ = snow
△ = rock
⏃ = woodsw
〰 = water
＊ = ice
〓 = wood
／ = door
☗ = gate
﹃ = ladder
Ⓓ = warp
⑵ = bulletin
⑸ = bulletin
⑹ = bulletin
⑺ = bulletin
⑻ = br_maxhp
⑼ = monument
⑾ = monument

; 敵情報
maxGroups = 2
monsters = ウインターコボルド,ウォーロック,ハーピーウィッチ
traps = 毒針,毒ガス,しびれ針,酸スプレー,爆弾,ラミアの瞳

; 移動ポイント
(A) = map:ノースロップ村, enter:ノースロップ村・北門, ask:Enter town?
(B) = map:フーラ雪原・氷の池, x:1, y:1, climb:true
(C) = map:鉱山Ｂ１, x:1, y:2, way:e, symbol:cave, ask:Go to the dungeon?
(D) = x:18, y:13
(E) = x:14, y:38

; 宝箱
box[1] = クレイモア_u,氷結の鈴_u,レイズデッドの魔法書_u,ライトストリームの魔法書_u,復活の粉_u,金貨（特大）
box[2] = 媚薬の霧,つるはし,アダマンタイト鉱石

